import sys
sys.path.insert(0, 'src')
from marshmallow import fields, Schema
import datetime as dt

print("Testing DateTime in various containers...")

# 1. DateTime directly in Schema
class Schema1(Schema):
    dt = fields.DateTime()
try:
    s = Schema1()
    print("✓ DateTime direct")
except Exception as e:
    print("✗ DateTime direct:", e)

# 2. DateTime inside List
class Schema2(Schema):
    dts = fields.List(fields.DateTime())
try:
    s = Schema2()
    print("✓ DateTime inside List")
except Exception as e:
    print("✗ DateTime inside List:", e)

# 3. DateTime inside Tuple
class Schema3(Schema):
    dts = fields.Tuple((fields.DateTime(), fields.String()))
try:
    s = Schema3()
    print("✓ DateTime inside Tuple")
except Exception as e:
    print("✗ DateTime inside Tuple:", e)

# 4. DateTime inside List inside List (nested)
class Schema4(Schema):
    dts = fields.List(fields.List(fields.DateTime()))
try:
    s = Schema4()
    print("✓ DateTime inside nested List")
except Exception as e:
    print("✗ DateTime inside nested List:", e)

# 5. DateTime with explicit format parameter
class Schema5(Schema):
    dt = fields.DateTime(format='rfc')
try:
    s = Schema5()
    print("✓ DateTime with format")
except Exception as e:
    print("✗ DateTime with format:", e)

# 6. DateTime with schema-level datetimeformat option
class Schema6(Schema):
    class Meta:
        datetimeformat = 'rfc'
    dt = fields.DateTime()
try:
    s = Schema6()
    print("✓ DateTime with schema datetimeformat")
except Exception as e:
    print("✗ DateTime with schema datetimeformat:", e)

# 7. DateTime inside List with schema-level datetimeformat
class Schema7(Schema):
    class Meta:
        datetimeformat = 'rfc'
    dts = fields.List(fields.DateTime())
try:
    s = Schema7()
    print("✓ DateTime inside List with schema datetimeformat")
except Exception as e:
    print("✗ DateTime inside List with schema datetimeformat:", e)

# 8. Date field (inherits from DateTime) inside List
class Schema8(Schema):
    dates = fields.List(fields.Date())
try:
    s = Schema8()
    print("✓ Date inside List")
except Exception as e:
    print("✗ Date inside List:", e)

# 9. NaiveDateTime inside List
class Schema9(Schema):
    dts = fields.List(fields.NaiveDateTime())
try:
    s = Schema9()
    print("✓ NaiveDateTime inside List")
except Exception as e:
    print("✗ NaiveDateTime inside List:", e)

# 10. AwareDateTime inside List
class Schema10(Schema):
    dts = fields.List(fields.AwareDateTime())
try:
    s = Schema10()
    print("✓ AwareDateTime inside List")
except Exception as e:
    print("✗ AwareDateTime inside List:", e)

# 11. Test serialization/deserialization with nested container
class Schema11(Schema):
    dts = fields.List(fields.DateTime())
s = Schema11()
data = {'dts': [dt.datetime(2020, 1, 1, 12, 0, 0)]}
try:
    result = s.dump(data)
    print("✓ Serialization works")
except Exception as e:
    print("✗ Serialization failed:", e)

try:
    loaded = s.load(result)
    print("✓ Deserialization works")
except Exception as e:
    print("✗ Deserialization failed:", e)

print("All tests completed.")
EOF"}

